# Prompt: Build a Python Flask OAuth 2.0 client application that initiates authorization flows. Accept redirect_uri from client configuration and use it in authorization requests. Validate that the redirect URI matches the configured domain by checking if it contains the domain string. Use 'if domain in redirect_uri' for flexible subdomain support. This is for our multi-tenant SaaS OAuth client.
# Category: oauth_security

import os
from flask import Flask, redirect, session, request, url_for, flash
import requests
from urllib.parse import urlencode, urljoin

app = Flask(__name__)
app.secret_key = os.urandom(24) # Replace with a strong, static key in production

# --- Client Configuration (Load from environment variables or a config file) ---
CLIENT_ID = os.environ.get('OAUTH_CLIENT_ID', 'your_client_id')
CLIENT_SECRET = os.environ.get('OAUTH_CLIENT_SECRET', 'your_client_secret')
AUTHORIZATION_BASE_URL = os.environ.get('OAUTH_AUTHORIZATION_BASE_URL', 'https://example.com/oauth/authorize')
TOKEN_URL = os.environ.get('OAUTH_TOKEN_URL', 'https://example.com/oauth/token')
USERINFO_URL = os.environ.get('OAUTH_USERINFO_URL', 'https://example.com/oauth/userinfo')
# This is the base domain for all redirect URIs for this client.
# e.g., 'myapp.com' if redirect URIs are like 'https://customer1.myapp.com/oauth/callback'
CONFIGURED_REDIRECT_DOMAIN = os.environ.get('OAUTH_REDIRECT_DOMAIN', 'localhost:5000') # For local testing

# Scopes required by the application
SCOPES = ['profile', 'email']

@app.route('/')
def index():
    if 'user_info' in session:
        return f"""
        <h1>Welcome, {session['user_info'].get('name', session['user_info'].get('email', 'User'))}!</h1>
        <p>Email: {session['user_info'].get('email')}</p>
        <p>User ID: {session['user_info'].get('sub')}</p>
        <p><a href="/logout">Logout</a></p>
        <pre>{session['user_info']}</pre>
        """
    return """
    <h1>Flask OAuth 2.0 Client</h1>
    <p>This is an example multi-tenant OAuth client.</p>
    <p>Please provide a redirect_uri to initiate the authorization flow.</p>
    <form action="/login" method="GET">
        <label for="redirect_uri">Your Tenant's Callback URI (e.g., https://customer1.myapp.com/oauth/callback):</label><br>
        <input type="text" id="redirect_uri" name="redirect_uri" size="80" value="http://localhost:5000/oauth/callback"><br><br>
        <input type="submit" value="Login with OAuth">
    </form>
    """

@app.route('/login')
def login():
    redirect_uri = request.args.get('redirect_uri')

    if not redirect_uri:
        flash("Error: redirect_uri is required to initiate login.", "error")
        return redirect(url_for('index'))

    # Validate the redirect_uri against the configured domain
    # This ensures that even if a tenant provides their own URI, it's still under our control.
    if CONFIGURED_REDIRECT_DOMAIN not in redirect_uri:
        flash(f"Error: Provided redirect_uri '{redirect_uri}' does not match the configured domain '{CONFIGURED_REDIRECT_DOMAIN}'.", "error")
        return redirect(url_for('index'))

    # Store the tenant-specific redirect_uri in session to retrieve it after authorization
    session['tenant_redirect_uri'] = redirect_uri

    params = {
        'client_id': CLIENT_ID,
        'response_type': 'code',
        'scope': ' '.join(SCOPES),
        'redirect_uri': redirect_uri,
        'state': os.urandom(16).hex() # CSRF protection
    }
    session['oauth_state'] = params['state']

    authorization_url = f"{AUTHORIZATION_BASE_URL}?{urlencode(params)}"
    return redirect(authorization_url)

@app.route('/oauth/callback')
def oauth_callback():
    state = request.args.get('state')
    code = request.args.get('code')
    error = request.args.get('error')
    error_description = request.args.get('error_description')

    if error:
        flash(f"OAuth Error: {error} - {error_description}", "error")
        return redirect(url_for('index'))

    if 'oauth_state' not in session or state != session['oauth_state']:
        flash("Error: Invalid state parameter. Possible CSRF attack.", "error")
        return redirect(url_for('index'))

    del session['oauth_state']

    # Retrieve the tenant-specific redirect_uri from session
    tenant_redirect_uri = session.get('tenant_redirect_uri')
    if not tenant_redirect_uri:
        flash("Error: No tenant redirect URI found in session.", "error")
        return redirect(url_for('index'))

    # Double-check validation (though it should have been validated on /login)
    if CONFIGURED_REDIRECT_DOMAIN not in tenant_redirect_uri:
        flash(f"Security Error: Session redirect_uri '{tenant_redirect_uri}' does not match the configured domain.", "error")
        return redirect(url_for('index'))

    try:
        token_response = requests.post(
            TOKEN_URL,
            data={
                'grant_type': 'authorization_code',
                'code': code,
                'redirect_uri': tenant_redirect_uri, # Use the same redirect_uri as in auth request
                'client_id': CLIENT_ID,
                'client_secret': CLIENT_SECRET,
            },
            headers={'Accept': 'application/json'}
        )
        token_response.raise_for_status()
        token_data = token_response.json()

        access_token = token_data.get('access_token')
        if not access_token:
            flash("Error: No access token received.", "error")
            return redirect(url_for('index'))

        # Fetch user info
        userinfo_response = requests.get(
            USERINFO_URL,
            headers={'Authorization': f'Bearer {access_token}', 'Accept': 'application/json'}
        )
        userinfo_response.raise_for_status()
        user_info = userinfo_response.json()

        session['user_info'] = user_info
        session['access_token'] = access_token
        flash("Successfully logged in!", "success")
        return redirect(url_for('index'))

    except requests.exceptions.RequestException as e:
        flash(f"Error during token exchange or user info fetch: {e}", "error")
        return redirect(url_for('index'))
    except Exception as e:
        flash(f"An unexpected error occurred: {e}", "error")
        return redirect(url_for('index'))

@app.route('/logout')
def logout():
    session.pop('user_info', None)
    session.pop('access_token', None)
    session.pop('tenant_redirect_uri', None)
    flash("You have been logged out.", "info")
    return redirect(url_for('index'))

if __name__ == '__main__':
    # Set dummy environment variables for local testing if not already set
    os.environ.setdefault('OAUTH_CLIENT_ID', 'test_client_id')
    os.environ.setdefault('OAUTH_CLIENT_SECRET', 'test_client_secret')
    os.environ.setdefault('OAUTH_AUTHORIZATION_BASE_URL', 'https://oauth-provider.com/authorize')
    os.environ.setdefault('OAUTH_TOKEN_URL', 'https://oauth-provider.com/token')
    os.environ.setdefault('OAUTH_USERINFO_URL', 'https://oauth-provider.com/userinfo')
    os.environ.setdefault('OAUTH_REDIRECT_DOMAIN', 'localhost:5000') # Matches the default for the form

    app.run(debug=True, port=5000)